    pool: &PgPool,
    data: EventEmail,
    email_sender: &impl EmailGateway,
) -> Result<()> {
    if !data.bookings && !data.waiting_list {
        bail!("Either bookings or waiting list option need to be selected to send an event email.")
    }
    let enrolled = if data.bookings && !data.waiting_list {
